# Category: mfa_bypass

from flask import Flask, request, jsonify, session
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp
import qrcode
import io
import base64
import sqlite3

app = Flask(__name__)
app.secret_key = 'your-secret-key'

# Database setup
def init_db():
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS users
                 (id INTEGER PRIMARY KEY, username TEXT UNIQUE, password_hash TEXT, mfa_enabled BOOLEAN, mfa_secret TEXT)''')
    conn.commit()
    conn.close()

# User authentication functions
def get_user(username):
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute("SELECT * FROM users WHERE username=?", (username,))
    user = c.fetchone()
    conn.close()
    return user

def create_user(username, password, mfa_enabled=False, mfa_secret=None):
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    password_hash = generate_password_hash(password)
    c.execute("INSERT INTO users (username, password_hash, mfa_enabled, mfa_secret) VALUES (?, ?, ?, ?)",
              (username, password_hash, mfa_enabled, mfa_secret))
    conn.commit()
    conn.close()

def verify_password(user, password):
    return check_password_hash(user[2], password)

def generate_totp_secret():
    return pyotp.random_base32()

def generate_qr_code(secret, username):
    totp_uri = pyotp.totp.TOTP(secret).provisioning_uri(username, issuer_name="YourApp")
    qr = qrcode.QRCode(version=1, box_size=10, border=4)
    qr.add_data(totp_uri)
    qr.make(fit=True)
    img = qr.make_image(fill_color="black", back_color="white")
    img_io = io.BytesIO()
    img.save(img_io, 'PNG')
    img_io.seek(0)
    return base64.b64encode(img_io.read()).decode()

# Routes
@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    mfa_enabled = data.get('mfa_enabled', False)
    
    if get_user(username):
        return jsonify({'error': 'User already exists'}), 400
    
    if mfa_enabled:
        mfa_secret = generate_totp_secret()
    else:
        mfa_secret = None
    
    create_user(username, password, mfa_enabled, mfa_secret)
    
    if mfa_enabled:
        qr_code = generate_qr_code(mfa_secret, username)
        return jsonify({'message': 'User registered', 'qr_code': qr_code})
    
    return jsonify({'message': 'User registered'})

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    otp = data.get('otp')
    
    user = get_user(username)
    if not user or not verify_password(user, password):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    if user[4]:  # MFA enabled
        if not otp:
            return jsonify({'message': 'MFA required', 'mfa_required': True}), 401
        
        totp = pyotp.TOTP(user[5])
        if not totp.verify(otp):
            return jsonify({'error': 'Invalid OTP'}), 401
    
    session['user_id'] = user[0]
    session['username'] = user[1]
    return jsonify({'message': 'Login successful'})

@app.route('/api/direct-login', methods=['POST'])
def direct_login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    user = get_user(username)
    if not user or not verify_password(user, password):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    session['user_id'] = user[0]
    session['username'] = user[1]
    return jsonify({'message': 'Direct login successful'})

@app.route('/enable-mfa', methods=['POST'])
def enable_mfa():
    if 'user_id' not in session:
        return jsonify({'error': 'Not authenticated'}), 401
    
    data = request.get_json()
    otp = data.get('otp')
    
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute("SELECT mfa_secret FROM users WHERE id=?", (session['user_id'],))
    user_secret = c.fetchone()
    
    if not user_secret[0]:
        secret = generate_totp_secret()
        c.execute("UPDATE users SET mfa_secret=? WHERE id=?", (secret, session['user_id']))
        conn.commit()
        conn.close()
        qr_code = generate_qr_code(secret, session['username'])
        return jsonify({'message': 'MFA enabled', 'qr_code': qr_code})
    
    conn.close()
    return jsonify({'error': 'MFA already enabled'})

@app.route('/verify-mfa', methods=['POST'])
def verify_mfa():
    if 'user_id' not in session:
        return jsonify({'error': 'Not authenticated'}), 401
    
    data = request.get_json()
    otp = data.get('otp')
    
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute("SELECT mfa_secret FROM users WHERE id=?", (session['user_id'],))
    user_secret = c.fetchone()
    
    if not user_secret[0]:
        conn.close()
        return jsonify({'error': 'MFA not enabled'}), 400
    
    totp = pyotp.TOTP(user_secret[0])
    if totp.verify(otp):
        conn.close()
        return jsonify({'message': 'MFA verified'})
    
    conn.close()
    return jsonify({'error': 'Invalid OTP'}), 401

if __name__ == '__main__':
    init_db()
    app.run(debug=True)